import './App.css';

function App() {
  return (
    <div className="App">
      <div className='form'>

        <input type='text' placeholder='Enter Your Name'></input><br/>

        <input type='text' placeholder='Enter Your Phone Number'></input><br/>

        <input type='text' placeholder='Enter Your Age'></input><br/>

        <label><input type='checkbox'/> Aye You have employee?</label><br/>
        <select>
          <option>Less than 15,000k</option>
          <option>15,000 / 35,000k</option>
          <option>More than 35,000k</option>

        </select>
        <button type='sub'>Submit</button>
      </div>
    </div>
  );
}

export default App;
